import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.C9sp7nFj.js";const n="/screenshots/tasks-list.jpeg",o="/screenshots/tasks-timer-running.jpeg",m=JSON.parse('{"title":"Tasks","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tasks.md","filePath":"guide/tasks.md","lastUpdated":1776880543000}'),r={name:"guide/tasks.md"};function c(h,e,l,d,g,u){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h1><p>See tasks assigned to you and track time on each.</p><div class="tip custom-block"><p class="custom-block-title">Ties to attendance</p><p>If your HR team has set <strong>Attendance Mode</strong> to <em>Timer Based</em>, starting a task timer here is the same as using the big <strong>Check In</strong> button with that task selected — server writes both the Timesheet row AND an <code>Employee Checkin (IN)</code>. If the mode is <em>Checkin Based</em> (the default), starting a timer here writes <strong>only</strong> the Timesheet row. See <strong><a href="/guide/attendance-mode">Attendance mode</a></strong>.</p></div><h2 id="open-tasks" tabindex="-1">Open Tasks <a class="header-anchor" href="#open-tasks" aria-label="Permalink to &quot;Open Tasks&quot;">​</a></h2><p>From the Home screen → <strong>Tasks</strong> quick action.</p><div class="screenshot-row"><figure class="screenshot"><img src="'+n+'" alt="Tasks list, idle"><figcaption>Tasks — idle state, every card has a Start Timer button and a priority chip.</figcaption></figure><figure class="screenshot"><img src="'+o+'" alt="Task timer running"><figcaption>Active task — live elapsed time and a red Stop Timer button replace Start.</figcaption></figure></div><h2 id="the-list" tabindex="-1">The list <a class="header-anchor" href="#the-list" aria-label="Permalink to &quot;The list&quot;">​</a></h2><p>Your assigned tasks appear with:</p><ul><li>Task name</li><li>Short description</li><li>Due date (if set)</li><li><strong>Start Timer</strong> button</li></ul><h2 id="starting-a-timer" tabindex="-1">Starting a timer <a class="header-anchor" href="#starting-a-timer" aria-label="Permalink to &quot;Starting a timer&quot;">​</a></h2><p>Tap <strong>Start Timer</strong> on a task. The timer begins counting and your IN check-in will be tagged to this task.</p><p>The stop button replaces Start while the timer is running — tap <strong>Stop Timer</strong> to end.</p><h2 id="geofence-on-tasks" tabindex="-1">Geofence on tasks <a class="header-anchor" href="#geofence-on-tasks" aria-label="Permalink to &quot;Geofence on tasks&quot;">​</a></h2><p>If your HR team has set a location + radius on the task, your check-ins are checked against it:</p><ul><li><strong>Inside the radius</strong> → geofence status <code>inside</code></li><li><strong>Outside the radius</strong> → <code>outside</code> (recorded but flagged for manager review)</li></ul><p>See the <a href="/guide/check-in#the-geofence-chip">Check-in page</a> for what this looks like on the Check-in screen.</p><h2 id="no-tasks-assigned" tabindex="-1">&quot;No tasks assigned.&quot; <a class="header-anchor" href="#no-tasks-assigned" aria-label="Permalink to &quot;&quot;No tasks assigned.&quot;&quot;">​</a></h2><p>If you see this message, your manager hasn&#39;t assigned any tasks to you yet. This is normal in some roles — you can still check in without a task.</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/check-in">Check-in &amp; Check-out</a></li><li><a href="/guide/attendance">Attendance calendar</a></li></ul>',20)])])}const p=t(r,[["render",c]]);export{m as __pageData,p as default};
